import { ethers } from 'ethers';

async function connectWallet() {
  if (window.ethereum) {
    try {
      await window.ethereum.request({ method: 'eth_requestAccounts' });
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      return provider.getSigner();
    } catch (error) {
      console.error('User denied account access', error);
    }
  } else {
    console.error('No Ethereum provider found');
  }
}

async function interactWithContract(contractAddress, abi, functionName, params) {
  const signer = await connectWallet();
  if (!signer) return;

  const contract = new ethers.Contract(contractAddress, abi, signer);
  try {
    const tx = await contract[functionName](...params);
    console.log('Transaction sent:', tx.hash);
    await tx.wait();
    console.log('Transaction confirmed:', tx.hash);
  } catch (error) {
    console.error('Transaction failed', error);
  }
}

document.getElementById('sendTransaction').addEventListener('click', async () => {
  const contractAddress = document.getElementById('contractAddress').value;
  const abi = JSON.parse(document.getElementById('contractABI').value);
  const functionName = document.getElementById('functionName').value;
  const params = JSON.parse(document.getElementById('params').value);

  await interactWithContract(contractAddress, abi, functionName, params);
});